// Password Protection logic
(function() {
  const correctPassword = 'Sage' + '123';
  
  function checkAccess() {
    const unlocked = sessionStorage.getItem('page_unlocked');
    const overlay = document.getElementById('passwordOverlay');
    if (unlocked === 'true') {
      if (overlay) overlay.remove();
      return;
    }
    
    if (!overlay) return;
    
    const input = document.getElementById('pagePasswordInput');
    const btn = document.getElementById('submitPasswordBtn');
    const err = document.getElementById('passwordError');
    
    function verify() {
      if (input.value === correctPassword) {
        sessionStorage.setItem('page_unlocked', 'true');
        overlay.remove();
      } else {
        err.style.display = 'block';
        input.value = '';
      }
    }
    
    btn.addEventListener('click', verify);
    input.addEventListener('keydown', e => {
      if (e.key === 'Enter') verify();
    });
  }
  
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', checkAccess);
  } else {
    checkAccess();
  }
})();

/* ── Build bento card HTML (Sage Intacct browser bar removed) ── */
function buildStripeCard({ large, span2, span3, eyebrow, title, body, blobs, uiContent }) {
  const colSpan = span3 ? 'bento-card--span3' : large ? 'bento-card--large' : span2 ? 'bento-card--span2' : '';
  const blobsHtml = (blobs || []).map(b =>
    `<div class="bento-stripe__blob" style="width:${b.w}px;height:${b.h}px;background:${b.color};top:${b.top};left:${b.left};right:${b.right || 'auto'};bottom:${b.bottom || 'auto'};"></div>`
  ).join('');
  return `
    <div class="bento-card bento-stripe ${colSpan}">
      <div class="bento-stripe__bg">${blobsHtml}</div>
      <div class="bento-stripe__copy">
        <div class="bento-stripe__eyebrow">${eyebrow}</div>
        <h4 class="bento-stripe__title">${title}</h4>
        <p class="bento-stripe__body">${body}</p>
      </div>
      <div class="bento-stripe__ui">
        ${uiContent}
      </div>
      <div class="bento-card__open-btn" aria-label="Open detail">+</div>
    </div>
  `;
}

function buildAppleCard({ large, span2, span3, eyebrow, title, body, uiContent }) {
  const colSpan = span3 ? 'bento-card--span3' : large ? 'bento-card--large' : span2 ? 'bento-card--span2' : '';
  return `
    <div class="bento-card bento-apple ${colSpan}">
      <div class="bento-apple__copy">
        <div class="bento-apple__eyebrow">${eyebrow}</div>
        <h4 class="bento-apple__title">${title}</h4>
        <p class="bento-apple__body">${body}</p>
      </div>
      <div class="bento-apple__ui">
        ${uiContent}
      </div>
      <div class="bento-card__open-btn" aria-label="Open detail">+</div>
    </div>
  `;
}

