  if (preset) {
    if (preset.businessVariables) {
      Object.assign(bv, preset.businessVariables);
    }
    Object.keys(preset).forEach(k => {
      if (k in bv && preset[k] && !String(preset[k]).startsWith('[')) {
        bv[k] = preset[k];
      }
    });
  }

  let vendorName = "Adobe Software";
