window.updateJournalAndAnomalies = function(industry = 'saas', turnover = '', employees = '', preset = null) {
  window.ANALYSIS_COMPLETED = false;
  let scale = 1.0;
  if (turnover) {
    const clean = turnover.toLowerCase();
    const num = parseFloat(clean.replace(/[^0-9.]/g, ''));
    if (!isNaN(num)) {
      if (clean.includes('b') || clean.includes('billion')) {
        scale = (num * 1000) / 10;
      } else if (clean.includes('m') || clean.includes('million')) {
        scale = num / 10;
      } else if (clean.includes('k') || clean.includes('thousand')) {
        scale = num / 10000;
      } else {
        scale = num / 10000000;
      }
    }
  }
  scale = Math.max(0.1, Math.min(20.0, scale));

  window.CURRENT_JOURNAL_ENTRIES = window.generateJournalEntries(industry, scale, preset);

  const duplicateRow = window.CURRENT_JOURNAL_ENTRIES.find(r => r.anomalyId === "anomaly-duplicate");
  const manualCashRow = window.CURRENT_JOURNAL_ENTRIES.find(r => r.anomalyId === "anomaly-manual-cash");
  const varianceRows = window.CURRENT_JOURNAL_ENTRIES.filter(r => r.anomalyId === "anomaly-variance");
  const thresholdRow = window.CURRENT_JOURNAL_ENTRIES.find(r => r.anomalyId === "anomaly-threshold");
  const concernRow = window.CURRENT_JOURNAL_ENTRIES.find(r => r.anomalyId === "anomaly-concern");

  window.CURRENT_AUDIT_ANOMALIES = [
    {
      id: "anomaly-manual-cash",
      type: "error",
      title: "Manual Override",
      description: `A ${manualCashRow ? (manualCashRow.txnAmount || manualCashRow.amount) : '-$450,000.00'} manual cash adjustment posted on a weekend date. Intentionally vague description.`,
      targetAccount: manualCashRow ? manualCashRow.account : "1010 - Cash & Cash Equivalents",
      rowIndexes: [9]
    },
    {
      id: "anomaly-threshold",
      type: "warning",
      title: "Threshold Bypass",
      description: `A transaction for ${thresholdRow ? (thresholdRow.txnAmount || thresholdRow.amount) : '$49,950.00'} sitting suspiciously just below a standard organizational threshold limit.`,
      targetAccount: thresholdRow ? thresholdRow.account : "6101 - Office Expense",
      rowIndexes: [12]
    },
    {
      id: "anomaly-saving",
      type: "success",
      title: "Saving Opportunity",
      description: "A recurring transaction for marketing retainer sitting at a high amount. You could save money here.",
      targetAccount: "2110 - Accounts Payable",
      rowIndexes: [16]
    }
  ];

  const hasConcern = window.BUSINESS_VARIABLES && window.BUSINESS_VARIABLES.BusinessConcern && !window.BUSINESS_VARIABLES.BusinessConcern.startsWith('[');
  if (hasConcern) {
    const label = getConcernSuggestedButtonText() || "Review operational efficiency";
    window.CURRENT_AUDIT_ANOMALIES.push({
      id: "anomaly-concern",
      type: "warning",
      title: label,
      description: `Potential compliance/operational variance: ${concernRow ? (concernRow.description || concernRow.desc) : 'Manual reclassification'} for ${concernRow ? (concernRow.txnAmount || concernRow.amount) : '$14,500.00'} at ${concernRow ? concernRow.entity : 'St. Jude Hospital'}.`,
      targetAccount: concernRow ? concernRow.account : "52100 - Surgical Supplies",
      rowIndexes: [8]
    });
  }

  if (typeof window.renderJournalRows === 'function') {
    window.renderJournalRows();
  }
};

window.updateJournalFromPersonalization = function(preset, presetIndustry) {
  let industry = presetIndustry ? presetIndustry.toLowerCase() : 'saas';
  const reason = (preset.reason || '').toLowerCase();
  const heroText = (preset.heroTitle || '').toLowerCase();
  
  if (!presetIndustry) {
    if (reason.includes('ngo') || reason.includes('non-profit') || reason.includes('charity') || heroText.includes('ngo') || heroText.includes('non-profit')) {
      industry = 'ngo';
    } else if (reason.includes('health') || reason.includes('clinic') || reason.includes('medical') || heroText.includes('health') || heroText.includes('clinic')) {
      industry = 'healthcare';
    } else if (reason.includes('construction') || reason.includes('build') || reason.includes('contractor') || heroText.includes('construction')) {
      industry = 'construction';
    } else if (reason.includes('saas') || reason.includes('software') || reason.includes('tech') || heroText.includes('saas') || heroText.includes('software')) {
      industry = 'saas';
    }
  }

  let turnover = preset.turnover || '';
  let employees = preset.employees || '';
  
  if (!turnover) {
    const combinedText = (preset.heroSub || '') + ' ' + (preset.reason || '');
    const turnMatch = combinedText.match(/\$\d+(\.\d+)?\s*(m|k|b|million|billion)/i);
    if (turnMatch) {
      turnover = turnMatch[0];
    }
  }

  window.updateJournalAndAnomalies(industry, turnover, employees, preset);
};

window.renderJournalRows = function() {
  const tbody = document.getElementById('journalTableBody');
  if (!tbody) return;
  if (!window.CURRENT_JOURNAL_ENTRIES) return;
  tbody.innerHTML = window.CURRENT_JOURNAL_ENTRIES.map((row, index) => {
    let trClass = row.style || '';
    const account = row.account || '';
    const date = row.postedDate || row.date || '';
    const desc = row.description || row.desc || '';
    const entity = row.entity || '';
    const currency = row.currency || '';
    const amountStr = String(row.txnAmount || row.amount || '');
    let tagHtml = '';
    let anomalyId = row.anomalyId || '';
    
    // Only show anomaly tags if Agent 3 analysis is completed
    if (window.ANALYSIS_COMPLETED) {
      if (anomalyId === 'anomaly-concern' || (row.anomalyId === 'anomaly-concern') || (desc.toLowerCase().includes('surgical mesh') && window.BUSINESS_VARIABLES && window.BUSINESS_VARIABLES.BusinessConcern && !window.BUSINESS_VARIABLES.BusinessConcern.startsWith('['))) {
        tagHtml = `<div style="margin-bottom: 4px;"><span style="background: #f59e0b; color: #78350f; padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: bold; display: inline-block;">[Needs Monitoring]</span></div>`;
        anomalyId = 'anomaly-concern';
        trClass = 'row-highlight-warning';
      } else if (amountStr.includes('49,950.00')) {
        tagHtml = `<div style="margin-bottom: 4px;"><span style="background: #f59e0b; color: #78350f; padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: bold; display: inline-block;">[Needs Monitoring]</span></div>`;
        if (!anomalyId) anomalyId = 'anomaly-threshold';
        trClass = 'row-highlight-warning';
      } else if (amountStr.includes('450,000.00') || desc.toLowerCase().includes('manual cash adj') || desc.toLowerCase().includes('unallocated')) {
        tagHtml = `<div style="margin-bottom: 4px;"><span style="background: #dc2626; color: white; padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: bold; display: inline-block;">[Critical Risk]</span></div>`;
        if (!anomalyId) anomalyId = 'anomaly-manual-cash';
        trClass = 'row-highlight-error';
      } else if (row.anomalyId) {
        tagHtml = `<span style="font-weight: 800; margin-right: 4px; color: ${trClass.includes('error') ? '#EF4444' : '#F59E0B'}">⚠</span>`;
      }
    }
    
    return `
      <tr id="journal-row-${index}" class="${trClass}" data-anomaly-id="${anomalyId}">
        <td>${tagHtml}${account}</td>
        <td>${desc}</td>
        <td>${entity}</td>
        <td>${amountStr}</td>
      </tr>
    `;
  }).join('');
};

window.selectAuditAnomaly = function(anomalyId) {
  console.log("Selecting anomaly:", anomalyId);
  const anomalyConfig = (window.CURRENT_AUDIT_ANOMALIES || []).find(a => a.id === anomalyId);
  if (!anomalyConfig) return;

  window.CURRENT_JOURNAL_ENTRIES.forEach((row, index) => {
    if (row.anomalyId === anomalyId) {
      row.style = anomalyConfig.type === 'error' ? 'row-highlight-error' : (anomalyConfig.type === 'success' ? 'row-highlight-success' : 'row-highlight-warning');
    } else {
      row.style = '';
    }
  });

  window.renderJournalRows();

  const rows = document.querySelectorAll('#journalTableBody tr');
  let firstTargetRow = null;
  rows.forEach(tr => {
    if (tr.getAttribute('data-anomaly-id') === anomalyId) {
      if (!firstTargetRow) firstTargetRow = tr;
    }
  });

  if (firstTargetRow) {
    const pane = document.getElementById('journalScrollContainer');
    if (pane) {
      const paneRect = pane.getBoundingClientRect();
      const rowRect = firstTargetRow.getBoundingClientRect();
      const relativeTop = rowRect.top - paneRect.top + pane.scrollTop;
      const targetScrollTop = relativeTop - (pane.clientHeight / 2) + (firstTargetRow.offsetHeight / 2);
      pane.scrollTo({
        top: Math.max(0, targetScrollTop),
        left: pane.scrollWidth,
        behavior: 'smooth'
      });
    }
    firstTargetRow.style.outline = '2px solid ' + (anomalyConfig.type === 'error' ? '#EF4444' : anomalyConfig.type === 'success' ? '#22C55E' : '#F59E0B');
    setTimeout(() => {
      firstTargetRow.style.outline = 'none';
    }, 1500);
  }

  document.querySelectorAll('.anomaly-interactive-card').forEach(card => {
    if (card.getAttribute('data-id') === anomalyId) {
      card.classList.add('is-active');
    } else {
      card.classList.remove('is-active');
    }
  });
};

// Initialize default journal and anomalies
window.updateJournalAndAnomalies();

function getConcernSuggestedButtonText() {
  const concern = (window.BUSINESS_VARIABLES && window.BUSINESS_VARIABLES.BusinessConcern) || "";
  if (!concern || concern.includes('[') || concern.trim() === '') return null;
  
  const lower = concern.toLowerCase();
  if (lower.includes('automate') || lower.includes('operational efficiency') || lower.includes('healthcare') || lower.includes('hospital')) {
    return "Review operational efficiency";
  } else if (lower.includes('multi-entity') || lower.includes('multi entity') || lower.includes('visibility')) {
    return "Review multi-entity visibility";
  } else if (lower.includes('ngo') || lower.includes('grant') || lower.includes('non profit') || lower.includes('charity')) {
    return "Review grant allocation compliance";
  } else if (lower.includes('construction') || lower.includes('job site') || lower.includes('subcontractor')) {
    return "Review subcontractor advances";
  } else if (lower.includes('saas') || lower.includes('subscription') || lower.includes('revenue')) {
    return "Review subscription revenue triggers";
  }
  
  // If there's an anomaly from Agent 2, use it
  const anomalies = window.CURRENT_AUDIT_ANOMALIES || [];
  const savingAnomaly = anomalies.find(a => a.id === "anomaly-saving" || a.type === "success");
  if (savingAnomaly) {
    return "Review " + savingAnomaly.title;
  }
  
  // Try to summarize the first 3 words
  const words = concern.trim().split(/\s+/);
  if (words.length > 0) {
    const cleanWords = words.slice(0, 3).map(w => w.replace(/[^a-zA-Z0-9]/g, ''));
    if (cleanWords.join(' ').trim() !== "") {
      return "Review " + cleanWords.join(' ');
    }
  }
  return "Review business concern";
}
window.getConcernSuggestedButtonText = getConcernSuggestedButtonText;

function initAssuranceAgentChatbot() {
  // Dynamic functions injection placeholder
  const container = document.getElementById('assuranceChatMessages');
  const input = document.getElementById('assuranceChatInput');
  const sendBtn = document.getElementById('assuranceChatSendBtn');
  const suggestedContainer = document.getElementById('assuranceSuggestedContainer');
  if (!container) return;

  if (!window.assuranceChatHistory) {
    window.assuranceChatHistory = [
      { sender: 'ai', text: "I monitor your books continuously and flag anomalies, risks, and audit compliance issues before they become problems." }
    ];
  }

  function renderSuggestions() {
    if (!suggestedContainer) return;
    suggestedContainer.innerHTML = '';
    
    // Hide suggestions once a user conversation starts
    const hasUserMessages = window.assuranceChatHistory.some(m => m.sender === 'user');
    if (hasUserMessages) {
      suggestedContainer.style.display = 'none';
      return;
    }
    
    const activeSuggestions = [];
    const concernBtnText = getConcernSuggestedButtonText();
    if (concernBtnText) {
      activeSuggestions.push(concernBtnText);
    }
    activeSuggestions.push("Are there any anomalies lately?");
    
    suggestedContainer.style.display = 'flex';
    activeSuggestions.forEach(text => {
      const btn = document.createElement('button');
      btn.className = 'chat-bubble-suggested';
      btn.style.width = '100%';
      btn.style.textAlign = 'left';
      btn.style.padding = '8px 12px';
      btn.style.fontSize = '11px';
      btn.style.fontWeight = '500';
      btn.style.margin = '2px 0';
      btn.style.backgroundColor = 'var(--primary-colors-accessible-jade)';
      btn.style.color = '#fff';
      btn.style.border = 'none';
      btn.style.borderRadius = '6px';
      btn.style.cursor = 'pointer';
      btn.textContent = text;
      btn.addEventListener('click', () => {
        handleUserSend(text);
      });
      suggestedContainer.appendChild(btn);
    });
  }

  function renderMessages() {
    container.innerHTML = '';
    window.assuranceChatHistory.forEach((msg, idx) => {
      if (msg.sender === 'ai') {
        const div = document.createElement('div');
        div.className = 'chat-bubble-ai';
        div.innerHTML = msg.text.replace(/\n/g, '<br/>');
        container.appendChild(div);

        // Detect anomaly association to add an inline scroll button inside the chat bubble
        let assocAnomalyId = msg.anomalyId || "";
        if (!assocAnomalyId) {
          const lowerText = msg.text.toLowerCase();
          if (lowerText.includes('manual cash') || lowerText.includes('weekend cash') || lowerText.includes('sunday manual') || lowerText.includes('manual override') || lowerText.includes('critical risk')) {
            assocAnomalyId = 'anomaly-manual-cash';
          } else if (lowerText.includes('threshold bypass') || lowerText.includes('threshold avoidance') || lowerText.includes('suspiciously just below') || lowerText.includes('limit of $50k') || lowerText.includes('procurement flag')) {
            assocAnomalyId = 'anomaly-threshold';
          } else if (lowerText.includes('save') || lowerText.includes('money') || lowerText.includes('cost') || lowerText.includes('optimize') || lowerText.includes('reducing') || lowerText.includes('saving') || lowerText.includes('retainer') || lowerText.includes('growth agency')) {
            assocAnomalyId = 'anomaly-saving';
          } else if (lowerText.includes('operational efficiency') || lowerText.includes('surgical mesh') || lowerText.includes('compliance variance') || lowerText.includes('business concern') || lowerText.includes('st. jude') || lowerText.includes('manual distribution') || lowerText.includes('force-balance') || lowerText.includes('clearance variance') || lowerText.includes('manual journal entry to force-balance')) {
            assocAnomalyId = 'anomaly-concern';
          }
        }

        if (assocAnomalyId) {
          const btn = document.createElement('button');
          btn.style.marginTop = '10px';
          btn.style.display = 'inline-flex';
          btn.style.alignItems = 'center';
          btn.style.gap = '6px';
          btn.style.fontSize = '11px';
          btn.style.fontWeight = '600';
          btn.style.padding = '6px 12px';
          btn.style.borderRadius = '6px';
          btn.style.border = 'none';
          btn.style.color = '#fff';
          btn.style.cursor = 'pointer';
          btn.style.transition = 'all 0.2s';
          
          let actionLabel = "Scroll & Highlight";
          if (assocAnomalyId === 'anomaly-saving') {
            btn.style.backgroundColor = '#16a34a';
            actionLabel = "🔍 Scroll to Saving Entry";
          } else if (assocAnomalyId === 'anomaly-manual-cash') {
            btn.style.backgroundColor = '#dc2626';
            actionLabel = "🔍 Scroll to Critical Risk";
          } else if (assocAnomalyId === 'anomaly-concern') {
            btn.style.backgroundColor = '#d97706';
            const shortLabel = getConcernSuggestedButtonText() || "Review business concern";
            actionLabel = "🔍 Scroll to " + shortLabel;
          } else {
            btn.style.backgroundColor = '#d97706';
            actionLabel = "🔍 Scroll to Threshold Bypass";
          }
          
          btn.innerHTML = actionLabel;
          btn.addEventListener('click', (e) => {
            e.preventDefault();
            window.selectAuditAnomaly(assocAnomalyId);
          });
          div.appendChild(btn);
        }

        const isLatestAi = (idx === window.assuranceChatHistory.length - 1);
        const isInitialWelcome = (idx === 0 && window.assuranceChatHistory.length === 1);
        const textLower = msg.text.toLowerCase();
        
        // Find user query preceding this AI response
        let userQuery = "";
        for (let i = idx - 1; i >= 0; i--) {
          if (window.assuranceChatHistory[i].sender === 'user') {
            userQuery = window.assuranceChatHistory[i].text.toLowerCase();
            break;
          }
        }
        
        const hasTrigger = (
          textLower.includes('anomaly') || 
          textLower.includes('anomalies') || 
          textLower.includes('issue') || 
          textLower.includes('problem') || 
          textLower.includes('flagged') || 
          textLower.includes('duplicate') || 
          textLower.includes('manual') || 
          textLower.includes('variance') || 
          textLower.includes('threshold') || 
          textLower.includes('error') ||
          textLower.includes('saving') ||
          textLower.includes('savings') ||
          textLower.includes('money') ||
          textLower.includes('cost') ||
          textLower.includes('optimize') ||
          textLower.includes('operational efficiency') ||
          textLower.includes('surgical supplies') ||
          textLower.includes('surgical mesh') ||
          textLower.includes('st. jude') ||
          textLower.includes('compliance') ||
          textLower.includes('efficiency') ||
          textLower.includes('vouchers') ||
          textLower.includes('force-balance') ||
          (getConcernSuggestedButtonText() && textLower.includes(getConcernSuggestedButtonText().toLowerCase()))
        );
        
        if (isLatestAi && hasTrigger && window.CURRENT_AUDIT_ANOMALIES && !isInitialWelcome) {
          const findingsWrapper = document.createElement('div');
          findingsWrapper.style.marginTop = '12px';
          findingsWrapper.style.display = 'flex';
          findingsWrapper.style.flexDirection = 'column';
          findingsWrapper.style.gap = '8px';
          
          // Reorder list to show queried/matching anomaly first
          let listToRender = [...window.CURRENT_AUDIT_ANOMALIES];
          let matchedId = null;
          if (userQuery) {
            if (userQuery.includes('save') || userQuery.includes('money') || userQuery.includes('cost') || userQuery.includes('optimize') || userQuery.includes('reducing') || userQuery.includes('saving')) {
              matchedId = 'anomaly-saving';
            } else if (userQuery.includes('manual') || userQuery.includes('cash') || userQuery.includes('sunday') || userQuery.includes('weekend')) {
              matchedId = 'anomaly-manual-cash';
            } else if (userQuery.includes('threshold') || userQuery.includes('bypass') || userQuery.includes('limit')) {
              matchedId = 'anomaly-threshold';
            } else if (userQuery.includes('operational efficiency') || userQuery.includes('surgical supplies') || userQuery.includes('surgical mesh') || userQuery.includes('st. jude') || userQuery.includes('vouchers') || userQuery.includes('force-balance') || userQuery.includes('compliance') || (getConcernSuggestedButtonText() && userQuery.includes(getConcernSuggestedButtonText().toLowerCase()))) {
              matchedId = 'anomaly-concern';
            }
          }
          
          if (matchedId) {
            listToRender.sort((a, b) => {
              if (a.id === matchedId) return -1;
              if (b.id === matchedId) return 1;
              return 0;
            });
          }
          
          listToRender.forEach((anom, aIdx) => {
            const card = document.createElement('div');
            card.className = `anomaly-interactive-card anomaly-${anom.type}`;
            card.setAttribute('data-id', anom.id);
            
            const badgeColor = anom.type === 'error' ? 'red' : (anom.type === 'success' ? 'green' : 'orange');
            const badgeLabel = anom.type === 'error' ? 'CRITICAL RISK' : (anom.type === 'success' ? 'SAVING OPPORTUNITY' : 'NEEDS MONITORING');
            
            card.innerHTML = `
              <div style="display: flex; justify-content: space-between; align-items: center;">
                <span class="anomaly-badge ${badgeColor}">${badgeLabel}</span>
                <span style="font-size: 9px; opacity: 0.6; font-family: monospace;">#${aIdx + 1}</span>
              </div>
              <div class="anomaly-title" style="font-family: 'Space Grotesk', sans-serif; font-weight: 600;">${anom.title}</div>
              <div class="anomaly-desc">${anom.description}</div>
            `;
            
            card.addEventListener('click', (e) => {
              e.preventDefault();
              window.selectAuditAnomaly(anom.id);
            });
            
            findingsWrapper.appendChild(card);
          });
          
          container.appendChild(findingsWrapper);
        }
      } else if (msg.sender === 'user') {
        const div = document.createElement('div');
        div.className = 'chat-bubble-user';
        div.textContent = msg.text;
        container.appendChild(div);
      }
    });
    // Scroll logic: if latest is from user, scroll to bottom. If from AI, do NOT auto-scroll anymore (as requested by user to prevent browser scroll).
    if (window.assuranceChatHistory.length > 0) {
      const lastMsg = window.assuranceChatHistory[window.assuranceChatHistory.length - 1];
      if (lastMsg.sender === 'user') {
        container.scrollTop = container.scrollHeight;
      }
    }
    renderSuggestions();
  }

  async function handleUserSend(text) {
    if (!text) return;
    const apiKey = localStorage.getItem('gemini_api_key') || '';
    const selectedModel = localStorage.getItem('gemini_model') || 'models/gemini-3.1-flash-lite';
    console.log("handleUserSend: calling model", selectedModel);
    
    window.assuranceChatHistory.push({ sender: 'user', text });
    renderMessages();

    // Check for product tour request first to skip LLM/Simulation and go straight to the tour modal
    const normText = text.toLowerCase();
    if (normText.includes('tour') || normText.includes('tuor') || normText.includes('walkthrough') || normText.includes('demo')) {
      const botResponse = "I'd be happy to show you how our continuous auditing and reconciliation features work! I've launched the personalized Sage Intacct product tour registration for you.";
      window.assuranceChatHistory.push({ sender: 'ai', text: botResponse });
      renderMessages();
      if (typeof window.openProductTourModal === 'function') {
        window.openProductTourModal();
      }
      if (window.logAgentInteraction) {
        window.logAgentInteraction("Assurance Agent (Local Detection)", "Local Logic", text, botResponse);
      }
      return;
    }

    const thinkingIdx = window.assuranceChatHistory.length;
    window.assuranceChatHistory.push({ sender: 'ai', text: "Analyzing 2026 ledger journal entries..." });
    renderMessages();

    let aiResponse = "";
    // DYNAMIC PROCESSING INNER START
    let logPayloadRequest = null;
    let logPayloadResponse = null;
    if (apiKey && apiKey.trim() && !apiKey.startsWith('YOUR_')) {
      try {
        const tableString = window.CURRENT_JOURNAL_ENTRIES.map(r => `${r.account} | ${r.description || r.desc} | ${r.entity} | ${r.currency} | ${r.txnAmount || r.amount}`).join('\n');
        const anomaliesString = window.CURRENT_AUDIT_ANOMALIES.map((a, i) => `${i+1}. ${a.title}: ${a.description}`).join('\n');
        
        const currentBvStr = JSON.stringify(window.BUSINESS_VARIABLES, null, 2);
        const systemPrompt = `You are the Sage Intacct Assurance Agent, an advanced continuous auditing AI system.
Your primary role is to audit the provided 20-row Journal Entry dataset dynamically generated by Agent 2 and identify, flag, and answer questions regarding internal control compliance issues.

Here is the exact Journal Entry dataset in context:
Account | Description | Entity | Posted Date | Currency | Txn Amount
${tableString}

We also have a memory of the company's "Business Profile" variables from discussions:
${currentBvStr}

CONVERSATION MEMORY & BUSINESS CONCERN CONSOLIDATION:
- Read the existing "BusinessConcern" value in the memory profile very carefully.
- As the conversation progresses, you MUST consolidate all business concerns, user preferences, operational realities, and any other relevant business information not captured by other variables into this "BusinessConcern" field.
- Append or merge new conversation points with the existing value so that you do not forget earlier parts of the conversation. Keep this field detailed and comprehensive (can be multiple paragraphs if there is rich discussion).
- CRITICAL RULES FOR WRITING THE "BusinessConcern" FIELD:
  1. It MUST ONLY summarize actual business concerns, pain points, financial visibility issues, and operational goals of the business.
  2. It MUST NOT include any description of actions, initialization status, continuous auditing oversight, or tracking behavior from the AI, the agent, or the system (e.g. do NOT write "The agent is now initialized and providing continuous auditing oversight...").
  3. It MUST NOT include requests or instructions that are not a business concern, such as requesting a product tour, asking for settings help, or clicking UI links (e.g. do NOT write "User also requested a product tour").
  4. It MUST NEVER use the word "the user" or "user" to refer to the company or client. You MUST always use the word "the business" instead.
- You MUST always output an updated YAML block containing the \`businessVariables\` object with the updated values at the end of your response, so that the system can automatically update its state and memory!
For example:
\`\`\`yaml
businessVariables:
  industry: "..."
  CompanySize: "..."
  CompanyTurnover: "..."
  BusinessConcern: "Consolidated business concern value..."
  journalVendorName: "..."
  journalHighRiskName: "..."
  journalApprovalName: "..."
  journalAccountPrefix: "..."
  journalMainEntity: "..."
  journalSecondaryEntity: "..."
\`\`\`

The data table visible to the user replaces old generic errors with explicit colored UI tags:
- "Critical Risk" (rendered in red) points to the weekend manual adjustment.
- "Needs Monitoring" (rendered in amber) points to the transaction circumventing standard authorization limits.
- "Saving Opportunity" (rendered in green) points to the marketing retainer candidate for renegotiation or cost saving.

STRICT REDUNDANCY EXCLUSION RULE:
- Do NOT include any text, headers, tags or copy matching '[Critical Risk: Manual Cash Adjustment detected]', '[Needs Monitoring: Unauthorized Procurement Flag]', or '[Saving Opportunity: Cost Optimization Flag]' in your text response. These are already displayed as UI elements and any inclusion in your text is highly redundant and strictly forbidden.

You must adapt to three distinct conversational interaction modes based on user prompts:

MODE 1: DIAGNOSTIC & ANALYSIS MODE (Consolidated)
Triggered when the user asks a validation question, specific questions regarding errors, risks, exceptions, cost saving, recommendations, or custom business concerns (e.g. "Are there any anomalies?", "How can I save money?", "Review operational efficiency", "What are your recommendations?", etc.).
- The agent should read the business variables, understand the business concerns, and answer the specific question asked in the chat, pinpointing precisely what is asked about in the journal entries.
- Depending on the type of answer, use the appropriate risk/compliance color code contextually:
  * RED (Critical Risk): Points to the manual cash adjustment override posted on a weekend date. Explain the internal control risk of weekend cash postings with vague descriptions.
  * AMBER (Needs Monitoring): Points to threshold bypasses (e.g., transaction just below CFO approval limit) or specific compliance/operational business concerns defined in the profile (such as reclassifying surgical supplies from inventory to expense, paper-based voucher distribution, force-balancing inter-entity variance, manual deferred subscription revenue tweaks, job site expense rental issues, etc.). Explain the operational inefficiency or bypass of procedures.
  * GREEN (Saving Opportunity): Points to renegotiating the marketing retainer to Growth Agency for $15,000. Explain how the business can optimize costs here.
- CRITICAL RULE: Keep your response professional, actionable, and strictly scoped to the available dataset context. Directly answer the user's question, pinpointing the specific entry and details.
- ACTION: You MUST append a YAML block with the matching action at the end of your response to allow the client interface to highlight and scroll directly to that row:
  * For saving inquiries: \`action: "anomaly-saving"\`
  * For manual cash weekend inquiries: \`action: "anomaly-manual-cash"\`
  * For threshold bypass inquiries: \`action: "anomaly-threshold"\`
  * For business concern / operational efficiency inquiries: \`action: "anomaly-concern"\`

MODE 2: DISCUSSION MODE
Triggered when the user asks open-ended, structural, or specific analytical follow-up questions (e.g., clicking on a recommendation card, asking about specific account balances, ledger dates, total outflows, or operational patterns).
- RULE: Provide professional, actionable accounting commentary restricted to 1-3 clear, concise sentences using the context from the customized ledger. Do not hesitate to reference exact figures or dates when discussing structural ledger traits.

MODE 3: PRODUCT TOUR REQUESTS
Triggered when the user asks for a product tour, walkthrough, or demo of Sage Intacct.
- RULE: Welcome the request warmly and immediately trigger the product tour. You MUST append a YAML block with \`action: "product_tour"\` at the end of your response, for example:
\`\`\`yaml
action: "product_tour"
\`\`\`
Do NOT refuse the request under any circumstances. Welcome them, and let them know you have launched the product tour.

Keep all answers professional, actionable, and strictly scoped to the available dataset context. Avoid any reference to old or inactive legacy anomalies (e.g., duplicate entries or elimination balance mismatches).`;

        const history = [];
        window.assuranceChatHistory.slice(0, thinkingIdx).forEach(m => {
          if (m.sender === 'user') {
            history.push({ role: 'user', parts: [{ text: m.text }] });
          } else if (m.sender === 'ai') {
            history.push({ role: 'model', parts: [{ text: m.text }] });
          }
        });

        const url = `https://generativelanguage.googleapis.com/v1beta/${selectedModel}:generateContent?key=${apiKey}`;
        const requestBody = {
          contents: history,
          systemInstruction: {
            parts: [{ text: systemPrompt }]
          }
        };

        const res = await fetch(url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(requestBody)
        });

        console.log("Gemini API Request:", { url, requestBody });
        
        if (!res.ok) {
          const errorText = await res.text();
          console.error("Gemini API Error Response:", errorText);
          throw new Error('HTTP Status ' + res.status + ': ' + errorText);
        }

        const resJson = await res.json();
        console.log("Gemini API Response:", resJson);

        if (resJson.candidates && resJson.candidates[0] && resJson.candidates[0].content && resJson.candidates[0].content.parts[0]) {
          aiResponse = resJson.candidates[0].content.parts[0].text;
          
          if (window.logAgentInteraction) {
            window.logAgentInteraction("Assurance Agent", selectedModel, requestBody, resJson);
          }

          // Parse any updated businessVariables returned by Agent 3
          const yamlMatch = aiResponse.match(/\`\`\`(?:yaml|json)\s*([\s\S]+?)\s*\`\`\`/i);
          const yamlFrontmatterMatch = aiResponse.match(/^---\s*([\s\S]+?)\s*---/m);
          if (yamlMatch || yamlFrontmatterMatch) {
            const yamlStr = yamlMatch ? yamlMatch[1] : yamlFrontmatterMatch[1];
            try {
              const parsed = jsyaml.load(yamlStr);
              if (parsed && parsed.action === 'product_tour') {
                if (typeof window.openProductTourModal === 'function') {
                  window.openProductTourModal();
                }
              }
              if (parsed && parsed.businessVariables) {
                Object.assign(window.BUSINESS_VARIABLES, parsed.businessVariables);
                window.updateBusinessVarsDisplay();
                // Dynamically update the ledger entries based on the new memory
                if (window.updateJournalFromPersonalization) {
                  window.updateJournalFromPersonalization(window.BUSINESS_VARIABLES);
                }
              }
            } catch (e) {
              console.error("Failed to parse business variables from Assurance Agent response:", e);
            }
          }
          
          aiResponse = aiResponse.replace(/\`\`\`(?:yaml|json|)(?:\s|.)*?\`\`\`/gi, '').replace(/^---\s*[\s\S]+?\s*---/m, '').trim();
          
          // Forcefully strip out redundant copies if the model outputs them despite instructions
          aiResponse = aiResponse
            .replace(/\[?Critical Risk:\s*Manual Cash Adjustment detected\]?/gi, '')
            .replace(/\[?Needs Monitoring:\s*Unauthorized Procurement Flag\]?/gi, '')
            .trim();

          // Intercept refusal phrasing if the model still outputs a refusal despite system instructions
          const lowerResp = aiResponse.toLowerCase();
          if (lowerResp.includes('cannot provide a product tour') || lowerResp.includes('strictly limited to') || lowerResp.includes('unable to provide a product tour')) {
            aiResponse = "I'd be happy to show you how our continuous auditing and reconciliation features work! I've launched the personalized Sage Intacct product tour registration for you.";
            if (typeof window.openProductTourModal === 'function') {
              window.openProductTourModal();
            }
          }
        } else {
          throw new Error('Invalid response format');
        }
      } catch (err) {
        console.error("Gemini call failed for Assurance Agent:", err);
        if (window.logAgentInteraction) {
          window.logAgentInteraction(
            "Assurance Agent (Agent 3 - Error)", 
            selectedModel, 
            { userPrompt: text }, 
            { error: err.message, status: "API call failed, running local simulation" }
          );
        }
        aiResponse = "";
      }
    }

    if (!aiResponse) {
      await new Promise(r => setTimeout(r, 700));
      const normText = text.toLowerCase();
      if (normText.includes('tour') || normText.includes('walkthrough') || normText.includes('demo')) {
        aiResponse = "I'd be happy to show you how our continuous auditing and reconciliation features work! I've launched the personalized Sage Intacct product tour registration for you.";
        setTimeout(() => {
          if (typeof window.openProductTourModal === 'function') {
            window.openProductTourModal();
          }
        }, 150);
      } else if (normText.includes('save') || normText.includes('money') || normText.includes('cost') || normText.includes('optimize') || normText.includes('reducing') || normText.includes('saving') || normText.includes('retainer')) {
        aiResponse = "I have identified a saving opportunity in your ledger entries: Our audit indicates that the recurring marketing retainer to Growth Agency (under Account 2110 - Accounts Payable for $15,000) is a prime candidate for renegotiation or consolidation. I have highlighted this entry in green for your review, and added a quick button below to scroll directly to it.";
      } else if (normText.includes('operational efficiency') || normText.includes('surgical supplies') || normText.includes('surgical mesh') || normText.includes('reclassify surgical') || normText.includes('st. jude') || normText.includes('manual distribution') || normText.includes('vouchers') || normText.includes('force-balance') || normText.includes('compliance variance') || normText.includes('review business concern') || (getConcernSuggestedButtonText() && normText.includes(getConcernSuggestedButtonText().toLowerCase()))) {
        const c = (window.CURRENT_AUDIT_ANOMALIES || []).find(a => a.id === 'anomaly-concern') || {};
        const account = c.targetAccount || "52100 - Surgical Supplies";
        const desc = c.description || "Potential compliance/operational variance.";
        
        let customExplanation = "Manual adjustments that bypass standard billing or procurement procedures introduce severe operational inefficiency and regulatory risk.";
        if (account.includes('52100')) {
          customExplanation = "Manual reclassification of surgical items directly to expenses bypasses surgical supply inventory logging and distorts true inventory valuations at St. Jude Hospital, indicating potential leakage or clinical record misalignment.";
        } else if (account.includes('5320')) {
          customExplanation = "Manual distribution of paper-based vouchers for field supplies bypasses standardized procurement tracking and grants compliance controls, exposing the organization to audit vulnerabilities under humanitarian mandates.";
        } else if (account.includes('13100')) {
          customExplanation = "Manual intercompany clearance entries force-balance multi-entity transactions to bypass system reconciliation procedures. This conceals true inter-entity variance and compromises consolidated visibility across subsidiary balances.";
        } else if (account.includes('4100')) {
          customExplanation = "Manual adjustments directly modifying deferred revenue contract tables violate standardized billing and contract triggers, bypassing ASC 606 revenue recognition standards and risking reporting inaccuracies.";
        } else if (account.includes('61030')) {
          customExplanation = "Entering unaccounted field equipment rentals manually bypassing formal purchase orders compromises budget oversight at job sites and obscures actual project margin visibility.";
        }
        
        aiResponse = `The transaction under account ${account} is flagged as a business concern compliance variance: ${desc} ${customExplanation}`;
      } else if (normText.includes('anomaly') || normText.includes('anomalies') || normText.includes('issue') || normText.includes('problem') || normText.includes('flagged') || normText.includes('error')) {
        const hasConcern = window.BUSINESS_VARIABLES && window.BUSINESS_VARIABLES.BusinessConcern && !window.BUSINESS_VARIABLES.BusinessConcern.startsWith('[');
        if (hasConcern) {
          aiResponse = "I have identified three key items in the 2026 ledger requiring review: one Critical Risk (Red), two items requiring Monitoring (Amber), and one Saving Opportunity (Green).";
        } else {
          aiResponse = "I have identified two anomalies in the 2026 ledger requiring review: one Critical Risk and one item requiring Monitoring.";
        }
      } else if (normText.includes('manual') || normText.includes('cash') || normText.includes('sunday') || normText.includes('weekend')) {
        const cash = (window.CURRENT_AUDIT_ANOMALIES || []).find(a => a.id === 'anomaly-manual-cash') || {};
        aiResponse = `Anomalous manual Cash entry detected: ${cash.description || "A manual cash adjustment posted on a weekend date."} under account ${cash.targetAccount || "1010 - Cash & Cash Equivalents"}. Direct cash overrides posted outside of standard business hours represent severe compliance and internal control risks.`;
      } else if (normText.includes('threshold') || normText.includes('limit') || normText.includes('avoidance') || normText.includes('bypass') || normText.includes('purchase')) {
        const t = (window.CURRENT_AUDIT_ANOMALIES || []).find(a => a.id === 'anomaly-threshold') || {};
        aiResponse = `The transaction under account ${t.targetAccount || "6101 - Office Expense"} is flagged as a potential threshold bypass: ${t.description || "A transaction sitting suspiciously just below a standard organizational threshold limit."} This suggests split invoicing to evade CFO sign-off limits.`;
      } else {
        const hasConcern = window.BUSINESS_VARIABLES && window.BUSINESS_VARIABLES.BusinessConcern && !window.BUSINESS_VARIABLES.BusinessConcern.startsWith('[');
        const shortLabel = getConcernSuggestedButtonText();
        aiResponse = `I've analyzed the 20 Journal Entries (posted dates in 2026). I can answer specific questions on manual weekend cash overrides, threshold evasions${hasConcern ? `, or the custom findings like "${shortLabel}"` : ''}. If you'd like full open-ended analysis, save your Gemini API key in the bottom-left chat settings!`;
      }

      // Consolidate simulated user concerns in Agent 3
      if (window.BUSINESS_VARIABLES) {
        const currentConcern = window.BUSINESS_VARIABLES.BusinessConcern || "";
        if (!currentConcern.toLowerCase().includes(text.toLowerCase())) {
          const timestamp = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
          const addedConcern = `[Assurance Audit Discussion at ${timestamp}]: ${text}`;
          window.BUSINESS_VARIABLES.BusinessConcern = currentConcern 
            ? `${currentConcern}\n\n${addedConcern}` 
            : addedConcern;
          window.updateBusinessVarsDisplay();
        }
      }

      if (window.logAgentInteraction) {
        window.logAgentInteraction("Assurance Agent (Simulated)", "Local Logic", text, aiResponse);
      }
    }

    window.assuranceChatHistory[thinkingIdx] = { sender: 'ai', text: aiResponse };
    renderMessages();
    if (!window.ANALYSIS_COMPLETED) {
      window.ANALYSIS_COMPLETED = true;
      if (typeof window.renderJournalRows === 'function') window.renderJournalRows();
    }

    // Auto pre-select the relevant finding on initial load or query trigger
    setTimeout(() => {
      const lowerText = text.toLowerCase();
      if (lowerText.includes('save') || lowerText.includes('money') || lowerText.includes('cost') || lowerText.includes('optimize') || lowerText.includes('reducing') || lowerText.includes('saving')) {
        window.selectAuditAnomaly('anomaly-saving');
      } else if (lowerText.includes('operational efficiency') || lowerText.includes('surgical mesh') || lowerText.includes('reclassify surgical') || lowerText.includes('st. jude') || lowerText.includes('manual distribution') || lowerText.includes('vouchers') || lowerText.includes('force-balance') || lowerText.includes('compliance variance') || lowerText.includes('review business concern') || (getConcernSuggestedButtonText() && lowerText.includes(getConcernSuggestedButtonText().toLowerCase()))) {
        window.selectAuditAnomaly('anomaly-concern');
      } else if (lowerText.includes('manual') || lowerText.includes('cash') || lowerText.includes('sunday') || lowerText.includes('weekend')) {
        window.selectAuditAnomaly('anomaly-manual-cash');
      } else if (lowerText.includes('threshold') || lowerText.includes('limit') || lowerText.includes('avoidance') || lowerText.includes('bypass') || lowerText.includes('purchase')) {
        window.selectAuditAnomaly('anomaly-threshold');
      } else if (window.CURRENT_AUDIT_ANOMALIES && window.CURRENT_AUDIT_ANOMALIES[0]) {
        window.selectAuditAnomaly(window.CURRENT_AUDIT_ANOMALIES[0].id);
      }
    }, 300);
  }

  if (sendBtn) {
    sendBtn.addEventListener('click', () => {
      const text = input.value.trim();
      if (text) {
        input.value = '';
        handleUserSend(text);
      }
    });
  }

  if (input) {
    input.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') {
        const text = input.value.trim();
        if (text) {
          input.value = '';
          handleUserSend(text);
        }
      }
    });
  }

  renderMessages();
}

function initFinancialsInteractive() {
  initAssuranceAgentChatbot();
  if (typeof window.renderJournalRows === 'function') window.renderJournalRows();
  const agentPills = document.querySelectorAll('.agent-pill');
  const agentScenes = document.querySelectorAll('.agent-scene');
  const agentExplainer = document.getElementById('agentExplainer');
  const cursor = document.getElementById('card1Cursor');

  if (card1AbortController) {
    card1AbortController.abort();
  }
  card1AbortController = new AbortController();
  const signal = card1AbortController.signal;

  if (!agentPills.length || !cursor) return;
  const cardContainer = cursor.closest('.bento-card');
  if (!cardContainer) return;

  let isAutoPlaying = true;
  agentPills.forEach(pill => {
    pill.addEventListener('click', () => {
      isAutoPlaying = false;
      cursor.style.opacity = '0';
      setActiveAgent(pill.dataset.key);
    });
  });

  function setActiveAgent(key) {
    agentPills.forEach(p => p.classList.remove('is-active'));
    const activePill = document.getElementById('c1Pill' + key.charAt(0).toUpperCase() + key.slice(1));
    if (activePill) activePill.classList.add('is-active');

    agentScenes.forEach(s => s.classList.remove('is-active'));
    const activeScene = document.getElementById('scene-' + key);
    if (activeScene) activeScene.classList.add('is-active');

    let text = "";
    if (key === 'close') {
      text = "<strong>Close:</strong> Accelerates close tasks / Accelerates your close.";
    } else if (key === 'ap') {
      text = "<strong>AP:</strong> Invoices code themselves.";
    } else if (key === 'assurance') {
      text = "<strong>Assurance:</strong> Monitors and flags risks.";
    } else if (key === 'time') {
      text = "<strong>Time:</strong> Auto-captures time accurately.";
    }
    if (agentExplainer) agentExplainer.innerHTML = text;
  }

  const sleep = ms => new Promise((resolve, reject) => {
    if (signal.aborted) {
      return reject(new Error('aborted'));
    }
    const timer = setTimeout(resolve, ms);
    signal.addEventListener('abort', () => {
      clearTimeout(timer);
      reject(new Error('aborted'));
    });
  });

  async function moveCursorTo(el) {
    if (!el || signal.aborted) return;
    const rect = el.getBoundingClientRect();
    const cardRect = cardContainer.getBoundingClientRect();
    const x = rect.left - cardRect.left + rect.width / 2;
    const y = rect.top - cardRect.top + rect.height / 2;
    cursor.style.left = `${x}px`;
    cursor.style.top = `${y}px`;
    cursor.style.opacity = '1';
    await sleep(1200);
  }

  async function runTimeline() {
    try {
      while (!signal.aborted) {
        if (!isAutoPlaying) break;

        // ── CLOSE SCENE ──
        const r1 = document.getElementById('c1CloseRow1');
        const r2 = document.getElementById('c1CloseRow2');
        const r3 = document.getElementById('c1CloseRow3');
        const c1 = document.getElementById('c1CloseCheck1');
        const c2 = document.getElementById('c1CloseCheck2');
        const c3 = document.getElementById('c1CloseCheck3');
        const ring = document.getElementById('c1CloseRing');

        if (r1 && r2 && r3 && c1 && c2 && c3 && ring) {
          r1.classList.remove('is-active'); r2.classList.remove('is-active'); r3.classList.remove('is-active');
          c1.classList.remove('is-checked'); c2.classList.remove('is-checked'); c3.classList.remove('is-checked');
          ring.style.background = `conic-gradient(var(--primary-colors-accessible-jade) 0%, #f0f0f0 0)`;
        }

        const pillClose = document.getElementById('c1PillClose');
        await moveCursorTo(pillClose);
        if (!isAutoPlaying) break;
        setActiveAgent('close');
        await sleep(1000);

        if (c1 && r1 && ring) {
          r1.classList.add('is-active');
          c1.classList.add('is-checked');
          ring.style.background = `conic-gradient(var(--primary-colors-accessible-jade) 33%, #f0f0f0 0)`;
          await sleep(800);
        }
        if (c2 && r2 && ring) {
          r2.classList.add('is-active');
          c2.classList.add('is-checked');
          ring.style.background = `conic-gradient(var(--primary-colors-accessible-jade) 66%, #f0f0f0 0)`;
          await sleep(800);
        }
        if (c3 && r3 && ring) {
          r3.classList.add('is-active');
          c3.classList.add('is-checked');
          ring.style.background = `conic-gradient(var(--primary-colors-accessible-jade) 100%, #f0f0f0 0)`;
          await sleep(800);
        }

        if (ring) {
          await moveCursorTo(ring);
          if (!isAutoPlaying) break;
          await sleep(2500);
        }

        // ── AP SCENE ──
        const invoice = document.getElementById('c1APInvoice');
        const vendor = document.getElementById('c1APVendor');
        const gl = document.getElementById('c1APGL');
        const badge = document.getElementById('c1APBadge');

        if (invoice && vendor && gl && badge) {
          invoice.classList.remove('is-scanning');
          vendor.classList.remove('is-filled');
          gl.classList.remove('is-filled');
          badge.classList.remove('is-visible');
          vendor.textContent = "";
          gl.textContent = "";
        }

        const pillAP = document.getElementById('c1PillAP');
        await moveCursorTo(pillAP);
        if (!isAutoPlaying) break;
        setActiveAgent('ap');
        await sleep(1000);

        if (invoice) {
          invoice.classList.add('is-scanning');
          await sleep(1500);
        }
        if (vendor) {
          vendor.classList.add('is-filled');
          vendor.textContent = "Acme Corp";
          await sleep(800);
        }
        if (gl) {
          gl.classList.add('is-filled');
          gl.textContent = "6100 - Office";
          if (badge) badge.classList.add('is-visible');
          await sleep(800);
        }
        if (badge) {
          await moveCursorTo(badge);
          if (!isAutoPlaying) break;
          await sleep(2500);
        }

        // ── ASSURANCE SCENE ──
        const assuranceRow = document.getElementById('c1AssuranceRow');
        const assuranceTooltip = document.getElementById('c1AssuranceTooltip');
        if (assuranceRow && assuranceTooltip) {
          assuranceRow.classList.remove('is-flagged');
          assuranceTooltip.classList.remove('is-visible');
        }

        const pillAssurance = document.getElementById('c1PillAssurance');
        await moveCursorTo(pillAssurance);
        if (!isAutoPlaying) break;
        setActiveAgent('assurance');
        await sleep(1000);

        if (assuranceRow) {
          assuranceRow.classList.add('is-flagged');
          await sleep(800);
          await moveCursorTo(assuranceRow);
          if (!isAutoPlaying) break;
          if (assuranceTooltip) assuranceTooltip.classList.add('is-visible');
          await sleep(3000);
        }

        // ── TIME SCENE ──
        const cells = [
          document.getElementById('c1TimeCell1'),
          document.getElementById('c1TimeCell2'),
          document.getElementById('c1TimeCell3'),
          document.getElementById('c1TimeCell4'),
          document.getElementById('c1TimeCell5')
        ];
        const timeSuccess = document.getElementById('c1TimeSuccess');
        cells.forEach(c => {
          if (c) {
            c.classList.remove('is-filled');
            c.textContent = "";
          }
        });
        if (timeSuccess) timeSuccess.classList.remove('is-visible');

        const pillTime = document.getElementById('c1PillTime');
        await moveCursorTo(pillTime);
        if (!isAutoPlaying) break;
        setActiveAgent('time');
        await sleep(1000);

        for (let i = 0; i < cells.length; i++) {
          const cell = cells[i];
          if (cell) {
            cell.classList.add('is-filled');
            cell.textContent = "8.0";
            await sleep(400);
          }
        }
        if (timeSuccess) {
          timeSuccess.classList.add('is-visible');
          await moveCursorTo(timeSuccess);
          if (!isAutoPlaying) break;
          await sleep(3000);
        }
      }
    } catch (err) {
      // Timeline aborted
    }
  }

  runTimeline();
}

