/* ── Scroll reveal ──────────────────────────────────────────── */
function initReveal() {
  const els = document.querySelectorAll('.reveal');
  if (!els.length) return;
  const io = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (e.isIntersecting) { e.target.classList.add('is-visible'); io.unobserve(e.target); }
    });
  }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' });
  els.forEach(el => io.observe(el));
}

/* ── Counter animation ──────────────────────────────────────── */
function animateCount(el, target, duration = 1200, suffix = '') {
  if (!el) return;
  const start = performance.now();
  const step = now => {
    const p = Math.min((now - start) / duration, 1);
    const eased = 1 - Math.pow(1 - p, 3);
    const val = Number.isInteger(target)
      ? Math.round(eased * target)
      : (eased * target).toFixed(1);
    el.textContent = val + suffix;
    if (p < 1) requestAnimationFrame(step);
    else el.textContent = target + suffix;
  };
  requestAnimationFrame(step);
}

function initCounters() {
  const els = document.querySelectorAll('.count-target');
  if (!els.length) return;
  const io = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        animateCount(e.target, parseFloat(e.target.dataset.val));
        io.unobserve(e.target);
      }
    });
  }, { threshold: 0.5 });
  els.forEach(el => io.observe(el));
}

/* ── Ask us anything Inactivity & Scroll handling ────────────── */
function initSearchPillInactivity() {
  const searchPill = document.getElementById('askCopilotForm');
  const searchInput = searchPill ? searchPill.querySelector('.hero__search-input') : null;
  const sparkleBtn = document.getElementById('aiSparkleToggle');
  if (!searchPill) return;

  let inactivityTimer;
  let pillVisible = false;
  let ignoreScrollUntil = 0;

  function showSearchPill(force = false) {
    if (force || window.scrollY < 300) {
      searchPill.classList.add('hero__search-pill--visible');
      if (sparkleBtn) {
        sparkleBtn.classList.remove('is-visible');
      }
      pillVisible = true;
    }
  }

  function hideSearchPill() {
    if (searchInput && document.activeElement === searchInput) return;
    searchPill.classList.remove('hero__search-pill--visible');
    pillVisible = false;
  }

  function handleScroll() {
    const chatPanel = document.getElementById('personalizationChatPanel');
    if (chatPanel && chatPanel.classList.contains('is-open')) {
      if (sparkleBtn) sparkleBtn.classList.remove('is-visible');
      searchPill.classList.remove('hero__search-pill--visible');
      return;
    }
    if (window.scrollY > 100) {
      if (window.scrollY > ignoreScrollUntil) {
        hideSearchPill();
        if (sparkleBtn) sparkleBtn.classList.add('is-visible');
      }
    } else {
      if (sparkleBtn) sparkleBtn.classList.remove('is-visible');
      if (!pillVisible) {
        clearTimeout(inactivityTimer);
        inactivityTimer = setTimeout(showSearchPill, 10000);
      }
    }
  }

  function resetInactivityTimer() {
    clearTimeout(inactivityTimer);
    inactivityTimer = setTimeout(showSearchPill, 10000);
  }

  if (sparkleBtn) {
    sparkleBtn.addEventListener('click', (e) => {
      e.preventDefault();
      clearTimeout(inactivityTimer);
      showSearchPill(true); // Force show the search pill, hiding the sparkle
      ignoreScrollUntil = window.scrollY + 100; // Ignore scroll hide until scrolled down further by 100px
    });
  }

  let throttleTimer;
  function throttledReset() {
    if (throttleTimer) return;
    throttleTimer = setTimeout(() => {
      resetInactivityTimer();
      throttleTimer = null;
    }, 300);
  }

  window.addEventListener('mousemove', throttledReset, {passive: true});
  window.addEventListener('keydown', resetInactivityTimer, {passive: true});
  window.addEventListener('click', resetInactivityTimer, {passive: true});
  window.addEventListener('scroll', handleScroll, {passive: true});

  inactivityTimer = setTimeout(showSearchPill, 10000);
}

/* ── Playable animated timeline ──────────────────────────────── */
class PlayableTimeline {
  constructor() {
    window.PLAYABLE_TIMELINE_INSTANCE = this;
    this.viewport = document.getElementById('screenViewport');
    this.cursor = document.getElementById('mockCursor');
    if (!this.viewport) return;

    this.steps = [
      { card: document.getElementById('step1'), rect: document.getElementById('stepBorderRect1'), icon: document.getElementById('stepIcon1') },
      { card: document.getElementById('step2'), rect: document.getElementById('stepBorderRect2'), icon: document.getElementById('stepIcon2') },
      { card: document.getElementById('step3'), rect: document.getElementById('stepBorderRect3'), icon: document.getElementById('stepIcon3') }
    ];

    this.steps.forEach(step => {
      if (step.rect) {
        const len = step.rect.getTotalLength ? step.rect.getTotalLength() : 736;
        step.length = len;
        step.rect.style.strokeDasharray = len;
        step.rect.style.strokeDashoffset = len;
      }
    });

    const resizeObserver = new ResizeObserver(entries => {
      entries.forEach(entry => {
        const stepCard = entry.target;
        const rectEl = stepCard.querySelector('.visual-step__border-rect');
        if (rectEl) {
          const w = stepCard.offsetWidth;
          const h = stepCard.offsetHeight;
          rectEl.setAttribute('x', '1.5');
          rectEl.setAttribute('y', '-1.5');
          rectEl.setAttribute('width', Math.max(0, w - 3).toString());
          rectEl.setAttribute('height', Math.max(0, h).toString());
          rectEl.setAttribute('rx', (h / 2).toString());
          rectEl.setAttribute('ry', (h / 2).toString());
          
          const len = rectEl.getTotalLength ? rectEl.getTotalLength() : (w * 2 + h * 2);
          const stepObj = this.steps.find(s => s.card === stepCard);
          if (stepObj) {
            stepObj.length = len;
            rectEl.style.strokeDasharray = len;
            if (stepCard.classList.contains('visual-step--completed')) {
              rectEl.style.strokeDashoffset = '0';
            } else if (!stepCard.classList.contains('visual-step--active')) {
              rectEl.style.strokeDashoffset = len.toString();
            }
          }
        }
      });
    });

    this.steps.forEach(step => {
      if (step.card) {
        resizeObserver.observe(step.card);
      }
    });

    this.screens = {
      checklist: document.getElementById('screenChecklist'),
      apReport: document.getElementById('screenAP'),
      invoice: document.getElementById('screenInvoice'),
      roi: document.getElementById('screenROI')
    };

    this.viewportCopilotToggle = document.getElementById('viewportCopilotToggle');
    this.copilotPrepareAPLink = document.getElementById('copilotPrepareAPLink');
    this.step1Copilot = document.getElementById('screenCopilot');
    this.step1CopilotTable = document.getElementById('copilotTableWrapper');
    this.step1PromptText = document.getElementById('copilotPromptText');
    this.copilotCloseAssistant = document.getElementById('copilotCloseAssistant');
    this.copilotVarianceReport = document.getElementById('copilotVarianceReport');
    
    this.invoicePO = document.getElementById('matchRowPO');
    this.invoiceRec = document.getElementById('matchRowRec');
    this.invoiceApproved = document.getElementById('invoiceApprovedBadge');
    this.invoiceBadge = document.getElementById('invoiceBadge');
    this.copilotInvoice = document.getElementById('copilotInvoice');
    this.copilotInvoiceText = document.getElementById('copilotInvoiceText');
    this.copilotInvoiceStats = document.getElementById('copilotInvoiceStats');
    this.roiMetricPeriod = document.getElementById('roiMetricPeriod');
    this.roiMetricSavings = document.getElementById('roiMetricSavings');
    this.roiBar1 = document.getElementById('roiBar1');
    this.roiBar2 = document.getElementById('roiBar2');
    this.roiBar3 = document.getElementById('roiBar3');
    this.copilotROI = document.getElementById('copilotROI');
    this.copilotROIText = document.getElementById('copilotROIText');

    this.activeStepIdx = 0;
    this.isPlaying = true;
    this.currentCycleAbort = null;

    this.initControls();
    this.playStep(0);
  }
  initControls() {
    this.steps.forEach((step, idx) => {
      // If clicking the play/pause icon specifically, toggle play/pause
      const iconWrap = step.card.querySelector('.visual-step__icon-wrapper');
      if (iconWrap) {
        iconWrap.addEventListener('click', e => {
          e.stopPropagation();
          if (this.activeStepIdx === idx) {
            this.togglePlayPause();
          } else {
            this.playStep(idx);
          }
        });
      }
      
      // Clicking on the card itself (including the AI color border) acts like seeking / picking sequence
      step.card.addEventListener('click', e => {
        e.stopPropagation();
        const rect = step.card.getBoundingClientRect();
        const clickX = e.clientX - rect.left;
        const ratio = Math.max(0, Math.min(1, clickX / rect.width));
        const duration = idx === 0 ? 7900 : idx === 1 ? 12500 : 13300;
        const seekTime = ratio * duration;
        this.playStep(idx, seekTime);
      });
    });
  }
  togglePlayPause() {
    this.isPlaying = !this.isPlaying;
    const s = this.steps[this.activeStepIdx];
    s.icon.textContent = this.isPlaying ? '⏸' : '▶';
    if (this.currentCycleAbort) {
      this.currentCycleAbort.paused = !this.isPlaying;
      if (this.isPlaying && this.currentCycleAbort.resumePromise) this.currentCycleAbort.resumePromise();
    }
  }

  async delay(ms, a) {
    let elapsed = 0;
    while (elapsed < ms) {
      if (a.aborted) throw new Error('aborted');
      if (a.paused) await new Promise(r => { a.resumePromise = r; });
      await new Promise(r => setTimeout(r, 20));
      elapsed += 20;
    }
  }

  getRelativeCoords(el) {
    if (!el) {
      console.warn("PlayableTimeline: Element is missing.");
      return { x: 0, y: 0 };
    }
    const vr = this.viewport.getBoundingClientRect();
    const er = el.getBoundingClientRect();
    return { x: er.left - vr.left + er.width / 2, y: er.top - vr.top + er.height / 2 };
  }

  async moveCursor(x, y, dur, a) {
    // Let CSS handle the transition (left/top 1.2s cubic-bezier set in .mock-cursor)
    this.cursor.style.left = `${x}px`;
    this.cursor.style.top = `${y}px`;
    this.cursor.style.opacity = '1';
    // Wait for the CSS transition to complete before continuing
    await this.delay(dur, a);
  }

  triggerClick(x, y) {
    const r = document.createElement('div');
    r.className = 'click-ripple';
    r.style.left = `${x}px`;
    r.style.top = `${y}px`;
    this.viewport.appendChild(r);
    setTimeout(() => r.remove(), 600);
  }

  async typeText(text, el, speed, a) {
    el.textContent = '';
    for (const ch of text) {
      if (a.aborted) throw new Error('aborted');
      if (a.paused) await new Promise(r => { a.resumePromise = r; });
      el.textContent += ch;
      await this.delay(speed, a);
    }
  }

  animateBorder(stepIdx, duration, abortObj) {
    const rect = this.steps[stepIdx].rect;
    const totalLen = this.steps[stepIdx].length;
    
    let elapsed = abortObj.seekTime || 0;
    let lastTime = Date.now();
    
    // Set initial dash offset instantly for seek preview
    const initialProgress = Math.min(elapsed / duration, 1);
    rect.style.strokeDashoffset = (totalLen * (1 - initialProgress)).toString();
    
    const interval = setInterval(() => {
      if (abortObj.aborted) {
        clearInterval(interval);
        return;
      }
      
      const now = Date.now();
      const delta = now - lastTime;
      lastTime = now;
      
      if (abortObj.paused) {
        return;
      }
      
      elapsed += delta;
      const progress = Math.min(elapsed / duration, 1);
      const offset = totalLen * (1 - progress);
      rect.style.strokeDashoffset = offset.toString();
      
      if (progress >= 1) {
        clearInterval(interval);
      }
    }, 30);
    
    abortObj.borderInterval = interval;
  }

  playStep(idx, seekTime = 0) {
    if (this.currentCycleAbort) {
      this.currentCycleAbort.aborted = true;
      if (this.currentCycleAbort.borderInterval) {
        clearInterval(this.currentCycleAbort.borderInterval);
      }
      if (this.currentCycleAbort.resumePromise) this.currentCycleAbort.resumePromise();
    }
    this.activeStepIdx = idx;
    this.isPlaying = true;
    this.currentCycleAbort = { aborted: false, paused: false, resumePromise: null, seekTime: seekTime };

    // Reset all copilot states and classes
    this.viewport.classList.remove('has-copilot-sidebar', 'has-copilot-reduced');
    this.copilotInvoice.classList.remove('screen-copilot-card--active');
    this.copilotROI.classList.remove('screen-copilot-card--active');
    this.copilotInvoiceStats.classList.remove('copilot-invoice-stats--active');
    this.copilotInvoiceText.textContent = '';
    this.copilotROIText.textContent = '';

    this.steps.forEach((s, i) => {
      s.card.classList.remove('visual-step--active', 'visual-step--completed');
      if (i < idx) {
        s.card.classList.add('visual-step--completed');
        s.icon.textContent = '✓';
        s.rect.style.strokeDashoffset = '0';
      } else {
        s.icon.textContent = '▶';
        s.rect.style.strokeDashoffset = s.length.toString();
      }
    });

    this.steps[idx].card.classList.add('visual-step--active');
    this.steps[idx].icon.textContent = '⏸';
    Object.keys(this.screens).forEach(k => this.screens[k].classList.remove('screen-card--active'));

    if (idx === 0) { this.screens.checklist.classList.add('screen-card--active'); this.runStep1(this.currentCycleAbort); }
    else if (idx === 1) { this.screens.invoice.classList.add('screen-card--active'); this.runStep2(this.currentCycleAbort); }
    else { this.screens.roi.classList.add('screen-card--active'); this.runStep3(this.currentCycleAbort); }
  }

  async runStep1(a) {
    try {
      const seek = a.seekTime || 0;
      
      // Reset classes & initial states
      this.viewport.classList.remove('has-copilot-sidebar', 'has-copilot-reduced');
      this.copilotCloseAssistant.classList.remove('copilot-sub-screen--hidden');
      this.copilotVarianceReport.classList.add('copilot-sub-screen--hidden');
      
      this.screens.apReport.classList.remove('screen-card--active');
      this.screens.checklist.classList.add('screen-card--active');
      this.screens.apReport.classList.add('ap-unreconciled');
      this.cursor.style.opacity = '0';
      
      // Start duration-based border animation
      this.animateBorder(0, 7900, a);
      
      // Position cursor above "Task owner" initially
      const thTaskOwner = document.getElementById('thTaskOwner');
      if (thTaskOwner) {
        const originalTransition = this.cursor.style.transition;
        this.cursor.style.transition = 'none';
        const startPos = this.getRelativeCoords(thTaskOwner);
        this.cursor.style.left = `${startPos.x}px`;
        this.cursor.style.top = `${startPos.y - 20}px`;
        this.cursor.offsetHeight; // force reflow
        this.cursor.style.transition = originalTransition;
      }
      
      // Phase 1: Wait initial 800ms
      if (seek < 800) {
        this.cursor.style.opacity = '1';
        await this.delay(800 - seek, a);
      }
      
      // Phase 2: Move cursor to Copilot button and click
      const t1 = this.getRelativeCoords(this.viewportCopilotToggle);
      if (seek < 2000) {
        this.cursor.style.opacity = '1';
        const remaining = Math.max(0, 2000 - Math.max(800, seek));
        await this.moveCursor(t1.x, t1.y, remaining, a);
        this.triggerClick(t1.x, t1.y);
        await this.delay(200, a);
      } else {
        this.cursor.style.left = `${t1.x}px`;
        this.cursor.style.top = `${t1.y}px`;
      }
      
      // Open Copilot Sidebar
      this.viewport.classList.add('has-copilot-sidebar');
      
      // Phase 3: Wait for sidebar opening (800ms)
      if (seek < 3000) {
        const remaining = Math.max(0, 3000 - Math.max(2200, seek));
        await this.delay(remaining, a);
      }
      
      // Phase 4: Move cursor to "Prepare AP reconciliation" and click
      const currentPrepareAPLink = document.getElementById('copilotPrepareAPLink') || this.copilotPrepareAPLink;
      const t2 = this.getRelativeCoords(currentPrepareAPLink);
      if (seek < 4200) {
        this.cursor.style.opacity = '1';
        const remaining = Math.max(0, 4200 - Math.max(3000, seek));
        await this.moveCursor(t2.x, t2.y, remaining, a);
        this.triggerClick(t2.x, t2.y);
        await this.delay(200, a);
      } else {
        this.cursor.style.left = `${t2.x}px`;
        this.cursor.style.top = `${t2.y}px`;
      }
      
      // Change screen to AP Subledger, show Copilot table
      this.cursor.style.opacity = '0';
      this.screens.checklist.classList.remove('screen-card--active');
      this.screens.apReport.classList.add('screen-card--active');
      this.copilotCloseAssistant.classList.add('copilot-sub-screen--hidden');
      this.copilotVarianceReport.classList.remove('copilot-sub-screen--hidden');
      
      // Phase 5: Wait 1000ms
      if (seek < 5400) {
        const remaining = Math.max(0, 5400 - Math.max(4400, seek));
        await this.delay(remaining, a);
      }
      
      // Phase 6: Collapse Copilot Sidebar, fill AP table reconciled values
      this.viewport.classList.remove('has-copilot-sidebar');
      this.viewport.classList.add('has-copilot-reduced');
      this.screens.apReport.classList.remove('ap-unreconciled');
      this.steps[0].rect.style.strokeDashoffset = '0';
      
      const totalDuration = 7900;
      if (seek < totalDuration) {
        const remaining = Math.max(0, totalDuration - Math.max(5400, seek));
        await this.delay(remaining, a);
      }
      
      this.playStep(1);
    } catch(e) {}
  }

  async runStep2(a) {
    try {
      const seek = a.seekTime || 0;
      this.cursor.style.opacity = '0';
      
      this.invoicePO.className = 'match-row';
      this.invoiceRec.className = 'match-row';
      ['matchDotPO','matchDotRec'].forEach(id => document.getElementById(id).className = 'match-dot');
      document.getElementById('matchStatusPO').textContent = 'Validating...';
      document.getElementById('matchStatusPO').className = 'match-status';
      document.getElementById('matchStatusRec').textContent = 'Pending...';
      document.getElementById('matchStatusRec').className = 'match-status';
      this.invoiceApproved.classList.remove('match-badge--active');
      this.copilotInvoice.classList.remove('screen-copilot-card--active');
      this.copilotInvoiceStats.classList.remove('copilot-invoice-stats--active');
      this.copilotInvoiceText.textContent = '';
      
      // Start duration-based border animation
      this.animateBorder(1, 12500, a);
      
      // Phase 1: Wait initial 800ms
      if (seek < 800) {
        await this.delay(800 - seek, a);
      }
      
      // Phase 2: Move cursor to invoicePO
      const t1 = this.getRelativeCoords(this.invoicePO);
      if (seek < 2000) {
        this.cursor.style.opacity = '1';
        const remaining = Math.max(0, 2000 - Math.max(800, seek));
        await this.moveCursor(t1.x, t1.y, remaining, a);
        this.triggerClick(t1.x, t1.y);
      } else {
        this.cursor.style.left = `${t1.x}px`;
        this.cursor.style.top = `${t1.y}px`;
      }
      
      this.invoicePO.classList.add('match-row--success');
      document.getElementById('matchDotPO').classList.add('match-dot--success');
      document.getElementById('matchStatusPO').textContent = 'Matched';
      document.getElementById('matchStatusPO').classList.add('match-status--success');
      
      // Phase 3: Wait 1000ms
      if (seek < 3000) {
        const remaining = Math.max(0, 3000 - Math.max(2000, seek));
        await this.delay(remaining, a);
      }
      
      // Phase 4: Move cursor to invoiceRec
      const t2 = this.getRelativeCoords(this.invoiceRec);
      if (seek < 4200) {
        this.cursor.style.opacity = '1';
        const remaining = Math.max(0, 4200 - Math.max(3000, seek));
        await this.moveCursor(t2.x, t2.y, remaining, a);
        this.triggerClick(t2.x, t2.y);
      } else {
        this.cursor.style.left = `${t2.x}px`;
        this.cursor.style.top = `${t2.y}px`;
      }
      
      this.invoiceRec.classList.add('match-row--success');
      document.getElementById('matchDotRec').classList.add('match-dot--success');
      document.getElementById('matchStatusRec').textContent = 'Matched';
      document.getElementById('matchStatusRec').classList.add('match-status--success');
      this.cursor.style.opacity = '0';
      
      // Phase 5: Wait 800ms
      if (seek < 5000) {
        const remaining = Math.max(0, 5000 - Math.max(4200, seek));
        await this.delay(remaining, a);
      }
      
      this.invoiceApproved.classList.add('match-badge--active');
      
      // Phase 6: Wait 800ms
      if (seek < 5800) {
        const remaining = Math.max(0, 5800 - Math.max(5000, seek));
        await this.delay(remaining, a);
      }
      
      // Phase 7: Move cursor to Approved badge and click
      const t3 = this.getRelativeCoords(this.invoiceApproved);
      if (seek < 7000) {
        this.cursor.style.opacity = '1';
        const remaining = Math.max(0, 7000 - Math.max(5800, seek));
        await this.moveCursor(t3.x, t3.y, remaining, a);
        this.triggerClick(t3.x, t3.y);
        await this.delay(200, a);
        this.cursor.style.opacity = '0';
      } else {
        this.cursor.style.left = `${t3.x}px`;
        this.cursor.style.top = `${t3.y}px`;
        this.cursor.style.opacity = '0';
      }
      
      // Phase 8: Wait 600ms
      if (seek < 7600) {
        const remaining = Math.max(0, 7600 - Math.max(7000, seek));
        await this.delay(remaining, a);
      }
      
      this.copilotInvoice.classList.add('screen-copilot-card--active');
      
      // Phase 9: Wait 800ms
      if (seek < 8400) {
        const remaining = Math.max(0, 8400 - Math.max(7600, seek));
        await this.delay(remaining, a);
      }
      
      this.copilotInvoiceText.innerHTML = window.PERSONALIZED_DATA.step2CopilotText;
      this.steps[1].rect.style.strokeDashoffset = '0';
      this.copilotInvoiceStats.classList.add('copilot-invoice-stats--active');
      
      const totalDuration = 12500;
      if (seek < totalDuration) {
        const remaining = Math.max(0, totalDuration - Math.max(8400, seek));
        await this.delay(remaining, a);
      }
      
      this.playStep(2);
    } catch(e) {}
  }

  async runStep3(a) {
    try {
      const seek = a.seekTime || 0;
      this.cursor.style.opacity = '0';
      
      const labelPeriod = document.getElementById('roiMetricPeriodLabel');
      if (labelPeriod) labelPeriod.textContent = window.PERSONALIZED_DATA.paybackPeriodLabel || 'Payback period';
      const labelSavings = document.getElementById('roiMetricSavingsLabel');
      if (labelSavings) labelSavings.textContent = window.PERSONALIZED_DATA.netSavingsLabel || 'Net savings';

      this.roiMetricPeriod.textContent = '0.0 mo';
      this.roiMetricSavings.textContent = '$0K';
      this.roiBar1.style.width = '0%';
      this.roiBar2.style.width = '0%';
      this.roiBar3.style.width = '0%';
      this.copilotROI.classList.remove('screen-copilot-card--active');
      this.copilotROIText.textContent = '';
      
      // Start duration-based border animation
      this.animateBorder(2, 13300, a);
      
      // Phase 1: Wait initial 800ms
      if (seek < 800) {
        await this.delay(800 - seek, a);
      }
      
      const paybackVal = window.PERSONALIZED_DATA.paybackPeriod || '5.8 mo';
      const parsedNum = parseFloat(paybackVal) || 5.8;
      const parsedSuffix = paybackVal.replace(String(parsedNum), '') || ' mo';
      const savingsVal = window.PERSONALIZED_DATA.netSavings || '$145k';

      // Phase 2: Animate counts
      if (seek < 2300) {
        animateCount(this.roiMetricPeriod, parsedNum, 1500, parsedSuffix);
        this.roiMetricSavings.textContent = savingsVal;
        await this.delay(1500, a);
      } else {
        this.roiMetricPeriod.textContent = paybackVal;
        this.roiMetricSavings.textContent = savingsVal;
      }
      
      // Phase 3: Wait 600ms
      if (seek < 2900) {
        const remaining = Math.max(0, 2900 - Math.max(2300, seek));
        await this.delay(remaining, a);
      }
      
      // Phase 4: Animate bars
      if (seek < 4100) {
        this.roiBar1.style.width = '25%';
        await this.delay(400, a);
        this.roiBar2.style.width = '60%';
        await this.delay(400, a);
        this.roiBar3.style.width = '100%';
        this.roiBar3.style.background = 'var(--primary-colors-brilliant-green)';
        await this.delay(400, a);
      } else {
        this.roiBar1.style.width = '25%';
        this.roiBar2.style.width = '60%';
        this.roiBar3.style.width = '100%';
        this.roiBar3.style.background = 'var(--primary-colors-brilliant-green)';
      }
      
      // Phase 5: Wait 800ms
      if (seek < 4900) {
        const remaining = Math.max(0, 4900 - Math.max(4100, seek));
        await this.delay(remaining, a);
      }
      
      this.copilotROI.classList.add('screen-copilot-card--active');
      this.copilotROIText.innerHTML = window.PERSONALIZED_DATA.step3CopilotText;
      this.steps[2].rect.style.strokeDashoffset = '0';
      
      const totalDuration = 13300;
      if (seek < totalDuration) {
        const remaining = Math.max(0, totalDuration - Math.max(4900, seek));
        await this.delay(remaining, a);
      }
      
      this.playStep(0);
    } catch(e) {}
  }
}


